def on_change_lstFiles():
    if lstFiles.selected_index >= 0:
        filename = lstFiles.items[lstFiles.selected_index]
        lblSelected.caption = f'Selected: {filename}'

def on_drag_start_lstFiles():
    if lstFiles.selected_index >= 0:
        filename = lstFiles.items[lstFiles.selected_index]
        lblStatus.caption = f'Dragging: {filename}'
        return filename

def on_drop_lstDestination():
    if drag_data:
        filename = drag_data
        lblStatus.caption = f'Dropped: {filename}'
        msgbox(f'Move {filename} to destination?', 'Confirm', 'yesno')

def on_click_btnOpen():
    filename = file_dialog('open', ['*'])
    if filename:
        lblSelected.caption = f'Opened: {filename}'
        lblStatus.caption = f'File: {filename}'
        # Add to recent files
        if filename not in lstFiles.items:
            lstFiles.items.append(filename)

def on_click_btnSave():
    filename = file_dialog('save', ['.txt', '.csv', '*'])
    if filename:
        lblSelected.caption = f'Save to: {filename}'
        lblStatus.caption = f'Ready to save: {filename}'

def on_click_btnInfo():
    if lstFiles.selected_index >= 0:
        filename = lstFiles.items[lstFiles.selected_index]
        size = file_size(filename)
        if size >= 0:
            if size < 1024:
                size_str = f'{size} B'
            elif size < 1024 * 1024:
                size_str = f'{size // 1024} KB'
            else:
                size_str = f'{size // (1024 * 1024)} MB'
            msgbox(f'File: {filename}\nSize: {size_str}', 'File Info')
        else:
            msgbox(f'Cannot get info for: {filename}', 'Error')
    else:
        msgbox('No file selected', 'Info')

