current_path = '.'
drag_data = None

def on_load_frmMain():
    global current_path
    current_path = '.'
    refresh_file_list()
    lblPath.caption = f'Current: {current_path}'

def refresh_file_list():
    global current_path
    try:
        files = list_files(current_path, '*')
        lstFiles.items = files
        lstFiles.scroll_offset = 0
        lblStatus.caption = f'Found {len(files)} items'
    except:
        lstFiles.items = []
        lblStatus.caption = 'Error reading directory'

def on_menu_mnuNewFolder():
    folder_name = inputbox('Folder name:', 'New Folder', 'newfolder')
    if folder_name:
        # In real implementation, would create directory
        msgbox(f'Would create folder: {folder_name}', 'New Folder')
        refresh_file_list()

def on_menu_mnuDelete():
    if lstFiles.selected_index >= 0:
        filename = lstFiles.items[lstFiles.selected_index]
        result = msgbox(f'Delete {filename}?', 'Confirm', 'yesno')
        if result == 'yes':
            # In real implementation, would delete file
            msgbox(f'Would delete: {filename}', 'Delete')
            refresh_file_list()
    else:
        msgbox('No file selected', 'Error')

def on_menu_mnuRefresh():
    refresh_file_list()
    lblStatus.caption = 'List refreshed'

def on_menu_mnuGoTo():
    global current_path
    new_path = inputbox('Enter path:', 'Go to', current_path)
    if new_path:
        current_path = new_path
        lblPath.caption = f'Current: {current_path}'
        refresh_file_list()
